-- Turkish Property System - Server Side\nlocal QBCore = exports['qb-core']:GetCoreObject()\n\nlocal PropertyDatabase = {\n    {id = 1, name = 'Taksim Apartmani', owner = nil, price = 450000, type = 'apartment', coords = {x = 425.0, y = -980.0, z = 29.0}},\n    {id = 2, name = 'Eminonu Dukkani', owner = nil, price = 650000, type = 'business', coords = {x = -520.0, y = -1020.0, z = 22.0}},\n    {id = 3, name = 'Kadikoy Villa', owner = nil, price = 1200000, type = 'house', coords = {x = 1150.0, y = -800.0, z = 57.0}},\n}\n\nRegisterNetEvent('property:server:buyProperty')\nAddEventHandler('property:server:buyProperty', function(propertyId)\n    local src = source\n    local Player = QBCore.Functions.GetPlayer(src)\n    if not Player then return end\n    \n    local property = PropertyDatabase[propertyId]\n    if not property or property.owner then return end\n    \n    if Player.PlayerData.money.cash < property.price then\n        TriggerClientEvent('QBCore:Notify', src, 'Yeterli paraniz yok!', 'error')\n        return\n    end\n    \n    property.owner = Player.PlayerData.citizenid\n    Player.Functions.RemoveMoney('cash', property.price)\n    TriggerClientEvent('QBCore:Notify', src, property.name .. ' satın alındı! $' .. property.price, 'success')\nend)\n\nprint('^2[Turkish Property System] Yuklendi!^7')"